"""SQLAlchemy model for Issue the Building Permit Certificate — generated by flowforge JTBD generator.

Do not edit by hand; rerun ``flowforge new`` (or the generator unit
tests) to regenerate. Edits should happen in the JTBD bundle.
"""

from __future__ import annotations

from datetime import datetime
from typing import Any

from sqlalchemy import (
	Boolean,
	Date,
	DateTime,
	Integer,
	Numeric,
	String,
	Text,
)
from sqlalchemy.orm import DeclarativeBase, Mapped, mapped_column


class Base(DeclarativeBase):
	"""Project-local declarative base; alembic upgrades target this metadata."""


class PermitIssuance(Base):
	__tablename__ = "permit_issuance"

	id: Mapped[str] = mapped_column(String(36), primary_key=True)
	tenant_id: Mapped[str | None] = mapped_column(String(36), nullable=True, index=True)
	state: Mapped[str] = mapped_column(String(64), nullable=False, default="intake")
	created_at: Mapped[datetime] = mapped_column(DateTime(timezone=True), nullable=False)
	updated_at: Mapped[datetime] = mapped_column(DateTime(timezone=True), nullable=False)
	permit_number: Mapped[Any] = mapped_column(String(512), nullable=False)
	issued_date: Mapped[Any] = mapped_column(Date(), nullable=False)
	clerk_signature: Mapped[Any] = mapped_column(String(128), nullable=False)
	fee_amount: Mapped[Any] = mapped_column(Numeric(18, 2), nullable=False)
	receipt_number: Mapped[Any] = mapped_column(String(512), nullable=False)

	def __repr__(self) -> str:  # pragma: no cover - cosmetic
		return f"<PermitIssuance id={self.id!r} state={self.state!r}>"
